// AVX2 optimized Q8_0: processes 32 values per block using 4 x 8-element lanes
void dequant_q8_0_avx2(const uint8_t* src, size_t n_elements, float* dst) {
    const size_t QK = 32;
    const size_t block_size = 2 + QK;
    size_t n_blocks = (n_elements + QK - 1) / QK;
    size_t out_index = 0;

    const __m256 one_ps = _mm256_set1_ps(1.0f);

    for (size_t b = 0; b < n_blocks; ++b) {
        size_t off = b * block_size;
        uint16_t scale_h;
        std::memcpy(&scale_h, src + off, sizeof(scale_h));
        float scale = half_to_float(scale_h);
        const uint8_t* vals_u8 = src + off + 2;
        const int8_t* vals = reinterpret_cast<const int8_t*>(vals_u8);

        __m256 scale_ps = _mm256_set1_ps(scale);

        size_t take = std::min(QK, n_elements - out_index);

        // process 4 * 8 = 32 values in 8-chunks
        size_t processed = 0;
        for (int lane = 0; lane < 4 && processed < take; ++lane) {
            const int8_t* ptr = vals + lane * 8;
            // load 8 bytes into lower 64-bit of __m128i
            __m128i chunk8 = _mm_loadl_epi64(reinterpret_cast<const __m128i*>(ptr)); // loads 8 bytes
            // sign-extend 8 int8 -> 8 int32 (in __m256i)
            __m256i i32 = _mm256_cvtepi8_epi32(chunk8);
            // convert to float
            __m256 f32 = _mm256_cvtepi32_ps(i32);
            // multiply by scale
            f32 = _mm256_mul_ps(f32, scale_ps);
            // store (may overshoot if take < 32; handle tail below)
            size_t store_count = std::min<size_t>(8, take - processed);
            if (store_count == 8) {
                _mm256_storeu_ps(dst + out_index + processed, f32);
            } else {
                // partial store: write into temporary then copy
                alignas(32) float tmp[8];
                _mm256_storeu_ps(tmp, f32);
                for (size_t k = 0; k < store_count; ++k) dst[out_index + processed + k] = tmp[k];
            }
            processed += store_count;
        }
        out_index += take;
    }
}
#endif // __AVX2__

// Scalar fallback: dequantize Q4_0
void dequant_q4_0_scalar(const uint8_t* src, size_t n_elements, float* dst) {
    const size_t QK = 32; // values per block
    const size_t block_size = 2 + QK/2; // 2 + 16
    size_t n_blocks = (n_elements + QK - 1) / QK;
    size_t out_index = 0;

    for (size_t b = 0; b < n_blocks; ++b) {
        size_t off = b * block_size;
        uint16_t scale_h;
        std::memcpy(&scale_h, src + off, sizeof(scale_h));
        float scale = half_to_float(scale_h);
        const uint8_t* packed = src + off + 2;
        size_t take = std::min(QK, n_elements - out_index);
        for (size_t j = 0; j < QK/2 && (2*j) < take; ++j) {
            uint8_t byte = packed[j];
            int low = (int)(byte & 0x0F) - 8;
            int high = (int)(byte >> 4) - 8;
            size_t idx0 = out_index + j*2;
            if (idx0 < out_index + take) dst[idx0] = float(low) * scale;
            if ((idx0 + 1) < out_index + take) dst[idx0 + 1] = float(high) * scale;
        }
        out_index += take;
    }
}

#ifdef __AVX2__
// AVX2-assisted Q4_0 dequantizer:
// - loads 16 packed bytes
// - vector-extract low nibbles and high nibbles into two vectors of 16 int16
// - converts halves to float vectors (2 x 8 -> 16 floats) for both low and high
// - finally interleaves low/high into dst (scalar interleave loop)
// Note: This avoids per-nibble scalar bit ops for the conversion step, but the final interleave is scalar.
// Further optimization can reduce the interleave cost (using shuffle/permutes) but this is clearer and efficient enough.
void dequant_q4_0_avx2(const uint8_t* src, size_t n_elements, float* dst) {
    const size_t QK = 32;
    const size_t block_size = 2 + QK/2; // 18
    size_t n_blocks = (n_elements + QK - 1) / QK;
    size_t out_index = 0;

    __m256i mask_0f = _mm256_set1_epi16(0x0F);
    for (size_t b = 0; b < n_blocks; ++b) {
        size_t off = b * block_size;
        uint16_t scale_h;
        std::memcpy(&scale_h, src + off, sizeof(scale_h));
        float scale = half_to_float(scale_h);
        const uint8_t* packed = src + off + 2;
        size_t take = std::min(QK, n_elements - out_index);

        // load 16 bytes
        __m128i bytes128 = _mm_loadu_si128(reinterpret_cast<const __m128i*>(packed)); // 16 bytes
        // expand to 16 uint16 lanes
        __m256i b16 = _mm256_cvtepu8_epi16(bytes128); // 16 x u16

        // low nibbles
        __m256i low16 = _mm256_and_si256(b16, mask_0f); // 16 x u16
        // high nibbles (shift right by 4)
        __m256i high16 = _mm256_srli_epi16(b16, 4);
        high16 = _mm256_and_si256(high16, mask_0f);

        // We need signed values in range -8..7: subtract 8
        __m256i sub8 = _mm256_set1_epi16(8);
        low16 = _mm256_sub_epi16(low16, sub8);
        high16 = _mm256_sub_epi16(high16, sub8);

        // Convert low16 (16 x int16) -> two sets of 8 x int32
        __m128i low_lo_128 = _mm256_castsi256_si128(low16);            // lanes 0..7 (int16)
        __m128i low_hi_128 = _mm256_extracti128_si256(low16, 1);       // lanes 8..15
        __m256i low32_0 = _mm256_cvtepi16_epi32(low_lo_128); // 8 x i32
        __m256i low32_1 = _mm256_cvtepi16_epi32(low_hi_128); // 8 x i32

        // Convert high16...
        __m128i high_lo_128 = _mm256_castsi256_si128(high16);
        __m128i high_hi_128 = _mm256_extracti128_si256(high16, 1);
        __m256i high32_0 = _mm256_cvtepi16_epi32(high_lo_128);
        __m256i high32_1 = _mm256_cvtepi16_epi32(high_hi_128);

        // Convert to float and multiply by scale
        __m256 scale_ps = _mm256_set1_ps(scale);

        __m256 lowf0 = _mm256_mul_ps(_mm256_cvtepi32_ps(low32_0), scale_ps); // floats 0..7 (low nibbles)
        __m256 lowf1 = _mm256_mul_ps(_mm256_cvtepi32_ps(low32_1), scale_ps); // floats 8..15

        __m256 highf0 = _mm256_mul_ps(_mm256_cvtepi32_ps(high32_0), scale_ps); // floats 0..7 (high nibbles)
        __m256 highf1 = _mm256_mul_ps(_mm256_cvtepi32_ps(high32_1), scale_ps); // floats 8..15

        // store into temporaries
        alignas(32) float tmp_low[16];
        alignas(32) float tmp_high[16];
        _mm256_storeu_ps(tmp_low + 0, lowf0);
        _mm256_storeu_ps(tmp_low + 8, lowf1);
        _mm256_storeu_ps(tmp_high + 0, highf0);
        _mm256_storeu_ps(tmp_high + 8, highf1);

        // Interleave into destination: [low0,high0, low1,high1, ...]
        size_t pairs = (take + 1) / 2; // number of (low,high) pairs relevant
        for (size_t j = 0; j < pairs; ++j) {
            size_t out_pos = out_index + j*2;
            if (out_pos < out_index + take) dst[out_pos] = tmp_low[j];
            if (out_pos + 1 < out_index + take) dst[out_pos + 1] = tmp_high[j];
        }

        out_index += take;
    }
}
#endif // __AVX2__

