//   - For production: add error checks, memory accounting, threadpool, and optimized GEMM kernels.

#include <sys/mman.h>
#include <sys/stat.h>
#include <fcntl.h>
#include <unistd.h>

#include <cstdint>
#include <cstring>
#include <iostream>
