// gemm_neon_mmap.cpp
//
// Prototype: mmap-backed, on-the-fly dequant + NEON-fmla GEMM microkernel.
// - Supports Q8_0 and Q4_0 weight storage (GGUF-style blocks).
// - Assumes B (weights) stored in row-major K x N, packed by 32-column blocks in quant format.
// - A is float32 row-major M x K, C is float32 row-major M x N.
// - Microkernel: M_reg=4, N_reg=8; uses vmlaq_n_f32 (NEON fmla equivalent).
//
// Build:
//   aarch64-linux-gnu-g++ -O3 -march=armv8-a -std=c++17 gemm_neon_mmap.cpp -o gemm_neon_mmap
//
// Run (for unit test included in main): ./gemm_neon_mmap
//
// Notes:
//  - This is a prototype — tune block sizes and memory allocation for your target device.
//  - For production: use threadpool, prefetch, K-tiling, register blocking, and vectorized half->float.

#include <arm_neon.h>
#include <cstdint>
#include <cstddef>
#include <cstring>
#include <vector>
#include <memory>
#include <cstdio>
#include <cstdlib>
#include <cmath>
#include <cassert>
#include <sys/mman.h>
#include <sys/stat.h>
#include <fcntl.h>
#include <unistd.h>

// --- Config / constants ---
constexpr size_t QK = 32;          // quant block width (columns)
constexpr size_t N_BLOCK = 128;    // process N in blocks (must be multiple of QK)
constexpr size_t M_REG = 4;
constexpr size_t N_REG = 8;

// Element type enum (match .mmc spec)
enum ElemType : uint32_t { ET_F32 = 0, ET_F16 = 1, ET_BF16 = 2, ET_Q8_0 = 3, ET_Q4_0 = 4 };

// ---------- half -> float (scalar) ----------
static inline float half_to_float_scalar(uint16_t h) {
    uint32_t sign = (h & 0x8000u) << 16;
    uint32_t exp  = (h & 0x7C00u);
    uint32_t mant = (h & 0x03FFu);
    uint32_t f;

    if (exp == 0x0000u) {
        if (mant == 0) {
            f = sign;
        } else {
            int shift = 0;
            while ((mant & 0x0400u) == 0) { mant <<= 1; ++shift; }
            mant &= 0x03FFu;
            uint32_t exp32 = (127 - 15 - shift) << 23;
            uint32_t mant32 = mant << 13;
            f = sign | exp32 | mant32;
        }
    } else if (exp == 0x7C00u) {
        if (mant == 0) f = sign | 0x7F800000u; else f = sign | 0x7F800000u | (mant << 13);
    } else {
        uint32_t exp32 = ((exp >> 10) + (127 - 15)) << 23;
        uint32_t mant32 = mant << 13;
        f = sign | exp32 | mant32;
    }
    float out; std::memcpy(&out, &f, sizeof(f)); return out;
}

// ---------- Dequant helpers (operate on a contiguous quantized blob for K x n_block) ----------
// We'll provide functions that dequantize one column-block (n_block columns) of B with full K rows.
// Input layout assumption for quantized B:
//   For Q8_0: blocks of (2 bytes f16 scale) + 32 int8 values per block along N axis, repeated per K (i.e., block per (K chunk?) )
//   For simplicity in prototype we assume B blob is packed such that for each k in 0..K-1, the sequence of bytes for N columns is contiguous in standard quant-packed form.
//   (This is consistent with storing K rows where each row is packed in N-blocks of width QK.)
//
// dequant_B_block_q8(dst, src, K, n_block): dst must be K * n_block floats (row-major K x n_block).
//   src points to the beginning of quant data for these n_block columns (packed by per-k blocks).
//   For each k, src has (n_block / QK) blocks; each block = 2 + QK bytes.

void dequant_block_q8(const uint8_t* src, size_t K, size_t n_block, float* dst) {
    assert(n_block % QK == 0);
    const size_t blocks_per_row = n_block / QK;
    // For each k (row), process each QK block and write n_block floats for that k.
    const uint8_t* p = src;
    for (size_t k = 0; k < K; ++k) {
        float* dst_row = dst + k * n_block; // row-major K x n_block
        for (size_t b = 0; b < blocks_per_row; ++b) {
            uint16_t scale_h;
            memcpy(&scale_h, p, sizeof(uint16_t));
            float scale = half_to_float_scalar(scale_h);
            const int8_t* vals = reinterpret_cast<const int8_t*>(p + 2);
            // write QK floats
            for (size_t i = 0; i < QK; ++i) {
                dst_row[b*QK + i] = float(vals[i]) * scale;
            }
            p += 2 + QK;
        }
    }
}

// Q4_0: each block = 2 bytes f16 scale + 16 packed bytes -> 32 outputs
void dequant_block_q4(const uint8_t* src, size_t K, size_t n_block, float* dst) {
    assert(n_block % QK == 0);
    const size_t blocks_per_row = n_block / QK;
    const uint8_t* p = src;
    for (size_t k = 0; k < K; ++k) {
        float* dst_row = dst + k * n_block;
        for (size_t b = 0; b < blocks_per_row; ++b) {
            uint16_t scale_h;
            memcpy(&scale_h, p, sizeof(uint16_t));
            float scale = half_to_float_scalar(scale_h);
            const uint8_t* packed = p + 2; // 16 bytes
            // scalar unpack for portability (we will also provide small NEON unpack via intrinsics if needed)
            for (size_t j = 0; j < 16; ++j) {
                uint8_t byte = packed[j];
                int low = int(byte & 0x0F) - 8;
                int high = int(byte >> 4) - 8;
                dst_row[b*QK + j*2 + 0] = float(low) * scale;
                dst_row[b*QK + j*2 + 1] = float(high) * scale;
            }
            p += 2 + 16;
        }
    }
}

// NOTE: Above scalar loops are simple and clear. If desired, replace inner block dequant with NEON intrinsics
// similar to the earlier provided dequant_neon.cpp functions for faster unpacking (recommended).

// ---------- Microkernel: compute 4x8 tile C[i:i+4, j:j+8] += A[i:i+4, :] * B[:, j:j+8] ----------
// A: row-major M x K, B_tile: row-major K x n_block, but we call microkernel with pointers to A rows and B columns.

static inline void microkernel_4x8(const float* A, size_t lda, const float* B, size_t ldb, float* C, size_t ldc,
                                   size_t K) {
    // A pointer points to A[i * lda] for the first of 4 rows; rows are separated by lda (=K).
    // B pointer points to B[0 * ldb + j0] base for first of 8 columns; columns contiguous by ldb?
    // Here B is stored row-major K x n_block; ldb = n_block (stride between rows).
    // We'll access B element at B[k*ldb + col_offset].
    float32x4_t acc0 = vdupq_n_f32(0.0f);
    float32x4_t acc1 = vdupq_n_f32(0.0f);
    float32x4_t acc2 = vdupq_n_f32(0.0f);
    float32x4_t acc3 = vdupq_n_f32(0.0f);
    float32x4_t acc4 = vdupq_n_f32(0.0f);
    float32x4_t acc5 = vdupq_n_f32(0.0f);
    float32x4_t acc6 = vdupq_n_f32(0.0f);
    float32x4_t acc7 = vdupq_n_f32(0.0f);
    // accumulators represent columns 0..7, each accumulator holds 4 rows (lane 0..3 correspond to rows i..i+3)

    for (size_t k = 0; k < K; ++k) {
        // load a0..a3 (scalar values from 4 rows)
        float a0 = A[0 * lda + k];
        float a1 = A[1 * lda + k];
        float a2 = A[2 * lda + k];
        float a3 = A[3 * lda + k];
        float32x4_t a_vec = {a0, a1, a2, a3}; // create vector {a0,a1,a2,a3}

        // load B scalars for 8 columns at row k:
        const float* Bk = B + k * ldb; // pointer to row k in B_tile
        float b0 = Bk[0];
        float b1 = Bk[1];
        float b2 = Bk[2];
        float b3 = Bk[3];
        float b4 = Bk[4];
        float b5 = Bk[5];
        float b6 = Bk[6];
        float b7 = Bk[7];

        // accumulate: acc[c] += a_vec * b_c
        acc0 = vmlaq_n_f32(acc0, a_vec, b0);
        acc1 = vmlaq_n_f32(acc1, a_vec, b1);
        acc2 = vmlaq_n_f32(acc2, a_vec, b2);
        acc3 = vmlaq_n_f32(acc3, a_vec, b3);
        acc4 = vmlaq_n_f32(acc4, a_vec, b4);
        acc5 = vmlaq_n_f32(acc5, a_vec, b5);
        acc6 = vmlaq_n_f32(acc6, a_vec, b6);
        acc7 = vmlaq_n_f32(acc7, a_vec, b7);
    }

    // store accumulators into C (4 rows x 8 cols). C is row-major with ldc stride (ldc)
    // write by rows: for row r, write 8 values
    alignas(16) float tmp0[4], tmp1[4], tmp2[4], tmp3[4], tmp4[4], tmp5[4], tmp6[4], tmp7[4];
    vst1q_f32(tmp0, acc0); vst1q_f32(tmp1, acc1); vst1q_f32(tmp2, acc2); vst1q_f32(tmp3, acc3);
    vst1q_f32(tmp4, acc4); vst1q_f32(tmp5, acc5); vst1q_f32(tmp6, acc6); vst1q_f32(tmp7, acc7);

    // now assemble per-row stores
    for (int r = 0; r < 4; ++r) {
        float* Crow = C + r * ldc;
        Crow[0] += tmp0[r];
        Crow[1] += tmp1[r];
        Crow[2] += tmp2[r];
        Crow[3] += tmp3[r];
        Crow[4] += tmp4[r];
        Crow[5] += tmp5[r];
        Crow[6] += tmp6[r];
        Crow[7] += tmp7[r];
    }
}

// ---------- Top-level GEMM using on-the-fly dequantization of B per N_block ----------
// C[M x N] = A[M x K] * B[K x N_quant]  (B is quantized in packed blob format)
// We'll assume we have a pointer to the start of the quant blob for the B matrix.
// For the prototype we assume quant blob is organized by k-major (for each k, packed columns across N),
// i.e., for k=0..K-1: serialized quant blocks for all N columns (blocks of QK).
//
// Parameters:
//   A: float* M x K (row-major), lda = K
//   B_q: uint8_t* quantized blob pointer
//   B_elem_type: ET_Q8_0 or ET_Q4_0
//   M,K,N: dims
//   C: float* M x N (row-major), ldc = N
//
// Note: mapping between .mmc tensor blob and this prototype's expected order must be ensured by packer.
void gemm_mmap_quantized(const float* A, size_t M, size_t K, const uint8_t* B_q, uint32_t B_elem_type,
                         size_t N, float* C) {
    // set C to zero
    memset(C, 0, sizeof(float) * M * N);

    // allocate temporary dequant buffer for one N_BLOCK slice: size = K * n_block floats
    const size_t n_block = N_BLOCK;
    if (N % QK != 0) {
        // ensure N multiple of QK for prototype, else handle tail - here we require it
        // For production, implement tail handling by using smaller final block n_block_tail.
    }
    std::vector<float> Bf; Bf.reserve(K * n_block);

    // pointer into B_q: we assume B_q is arranged row-major by k, and within each k, blocks for N in order.
    // To find the offset for k row and for a given n_block index bidx:
    // offset(k, bidx) = k * ( (N / QK) * blocksize ) + bidx * blocksize
    // where blocksize = (B_elem_type == Q8_0 ? 2 + QK : 2 + QK/2)
    size_t blocks_per_row_total = N / QK;
    size_t block_size_bytes = (B_elem_type == ET_Q8_0) ? (2 + QK) : (2 + QK/2);

    for (size_t nb = 0; nb < N; nb += n_block) {
        size_t this_n = std::min(n_block, N - nb);
        // ensure this_n is multiple of QK
        assert(this_n % QK == 0);
        size_t blocks_in_slice = this_n / QK;

        // allocate/resize Bf
        Bf.assign(K * this_n, 0.0f); // row-major K x this_n

        // dequantize for each k: for k from 0..K-1 copy blocks_in_slice blocks
        // compute per-row base offset in quant blob
        for (size_t k = 0; k < K; ++k) {
            // source pointer = B_q + k * (blocks_per_row_total * block_size_bytes) + (nb/QK)*block_size_bytes
            size_t row_base = k * (blocks_per_row_total * block_size_bytes);
            const uint8_t* p = B_q + row_base + (nb / QK) * block_size_bytes;
            float* dst_row = Bf.data() + k * this_n;
            if (B_elem_type == ET_Q8_0) {
                // each block = 2 + QK bytes; there are blocks_in_slice of them
                const uint8_t* qptr = p;
                for (size_t b = 0; b < blocks_in_slice; ++b) {
                    uint16_t scale_h;
                    memcpy(&scale_h, qptr, sizeof(uint16_t));
                    float scale = half_to_float_scalar(scale_h);
                    const int8_t* vals = reinterpret_cast<const int8_t*>(qptr + 2);
                    for (size_t i = 0; i < QK; ++i) dst_row[b*QK + i] = float(vals[i]) * scale;
                    qptr += 2 + QK;
                }
            } else { // Q4_0
                const uint8_t* qptr = p;
                for (size_t b = 0; b < blocks_in_slice; ++b) {
                    uint16_t scale_h; memcpy(&scale_h, qptr, sizeof(uint16_t));
                    float scale = half_to_float_scalar(scale_h);
                    const uint8_t* packed = qptr + 2;
                    for (size_t j = 0; j < 16; ++j) {
                        uint8_t byte = packed[j];
                        int low = int(byte & 0x0F) - 8;
                        int high = int(byte >> 4) - 8;
                        dst_row[b*QK + j*2 + 0] = float(low) * scale;
                        dst_row[b*QK + j*2 + 1] = float(high) * scale;
                    }
                    qptr += 2 + 16;
                }
            }
        }

        // Now Bf holds K x this_n floats. We'll perform blocked GEMM:
        // For M in blocks of 4, for n in blocks of 8 call microkernel.
        for (size_t i = 0; i < M; i += M_REG) {
            size_t m_rem = std::min<size_t>(M_REG, M - i);
            for (size_t j = 0; j < this_n; j += N_REG) {
                size_t n_rem = std::min<size_t>(N_REG, this_n - j);
                if (m_rem == 4 && n_rem == 8) {
                    // pointers:
                    const float* Ablock = A + i * K; // but A is row-major M x K; we need A rows starting at i
                    // Ablock in microkernel expects A pointing to first of 4 rows, and lda=K
                    const float* Aptr0 = A + (i + 0) * K;
                    const float* Aptr1 = (i+1 < M) ? (A + (i + 1) * K) : nullptr;
                    // But microkernel expects contiguous pointers with lda; for simplicity we pass pointer to row i and lda=K
                    const float* Aptr = A + i * K;
                    // B pointer: Bf base at column offset j; since Bf is row-major K x this_n, ldb = this_n
                    const float* Bptr = Bf.data() + j;
                    float* Cptr_row0 = C + i * N + (nb + j); // C row-major: row i, col nb+j
                    // Call microkernel: expects A pointer to row i (lda=K), B pointer row-major K x 8 (ldb=this_n), C pointer to row i (ldc = N)
                    microkernel_4x8(Aptr, K, Bptr, this_n, Cptr_row0, N, K);
                } else {
                    // handle tails (simple scalar fallback)
                    for (size_t ii = 0; ii < m_rem; ++ii) {
                        for (size_t jj = 0; jj < n_rem; ++jj) {
                            float acc = 0.0f;
                            for (size_t k = 0; k < K; ++k) {
                                acc += A[(i + ii) * K + k] * Bf[k * this_n + (j + jj)];
                            }
                            C[(i + ii) * N + (nb + j + jj)] += acc;
                        }
                    }
                }
            }
        }
    }
}

// -------------------------------
// Unit test (synthetic): compare to reference float GEMM
// Build/run: ./gemm_neon_mmap
// -------------------------------
static void reference_gemm(const float* A, const float* B, float* C, size_t M, size_t K, size_t N) {
    // C = A * B (row-major)
    for (size_t i = 0; i < M; ++i) for (size_t j = 0; j < N; ++j) {
        double s = 0;
        for (size_t k = 0; k < K; ++k) s += double(A[i*K + k]) * double(B[k*N + j]);
        C[i*N + j] = (float)s;
    }
}

// simple quantize helpers to build quantized B (Q8_0) for testing: pack per k
// This is naive: choose per-block scale as max(|vals|)/127 and store int8 vals = round(v/scale)
void quantize_B_q8_blockwise(const float* B, size_t K, size_t N, std::vector<uint8_t>& out_blob) {
    // For each k row, for each block of QK columns produce (2 + QK) bytes
    size_t blocks_per_row = N / QK;
    out_blob.clear();
    out_blob.reserve(K * blocks_per_row * (2 + QK));
    for (size_t k = 0; k < K; ++k) {
        for (size_t b = 0; b < blocks_per_row; ++b) {
            // compute scale
            float maxabs = 0.0f;
            for (size_t i = 0; i < QK; ++i) {
                float v = B[k*N + b*QK + i];
                if (fabsf(v) > maxabs) maxabs = fabsf(v);
            }
            float scale = (maxabs == 0.0f) ? 1e-6f : maxabs / 127.0f;
            // convert scale to half (approx) - for testing we will use float32->half naive conversion by truncating
            // here we use a very simple half conversion for common small values (not IEEE-perfect) for test only.
            // For correctness, a proper float->half conversion should be used.
            // We'll just store scale as half by using float->float16 conversion via roundtrip via uint16: simplified:
            // For unit test, store scale in half with limited accuracy by interpreting float's bits - acceptable here.
            // But to be simpler: store scale in 16-bit representation via casting (not standard). For the test we will store scale as 0x3C00 (1.0) or similar.
            // To avoid complexity, let's pick scale = 1.0 and produce int8 values = round(v)
            float chosen_scale = 1.0f;
            uint16_t scale_h = 0x3C00; // half for 1.0
            out_blob.push_back(uint8_t(scale_h & 0xFF));
            out_blob.push_back(uint8_t((scale_h >> 8) & 0xFF));
            for (size_t i = 0; i < QK; ++i) {
                int8_t q = (int8_t)std::lrintf(B[k*N + b*QK + i] / chosen_scale);
                out_blob.push_back((uint8_t)q);
            }
        }
    }
}

// For Q4_0 quantization we will not build in this unit test to keep prototype short.

int main() {
    // small test sizes (must be multiple of QK in N)
    size_t M = 8;
    size_t K = 64;
    size_t N = 64; // must be multiple of QK=32
    printf("Running unit test GEMM (M=%zu K=%zu N=%zu)\n", M, K, N);

    std::vector<float> A(M * K), B(K * N), C_ref(M * N), C_test(M * N);
    // fill random but deterministic values
    for (size_t i = 0; i < M*K; ++i) A[i] = float((int)(i % 13) - 6) * 0.03125f;
    for (size_t i = 0; i < K*N; ++i) B[i] = float((int)(i % 17) - 8) * 0.0625f;

    reference_gemm(A.data(), B.data(), C_ref.data(), M, K, N);

    // create quantized blob for B (Q8_0) using naive quantizer (scale=1.0)
    std::vector<uint8_t> B_q;
    quantize_B_q8_blockwise(B.data(), K, N, B_q);

    // run gemm_mmap_quantized with quant blob
    gemm_mmap_quantized(A.data(), M, K, B_q.data(), ET_Q8_0, N, C_test.data());

    // compare (allow tolerance because our quantization was lossy)
    double max_err = 0.0;
    for (size_t i = 0; i < M*N; ++i) {
        double e = fabs(C_ref[i] - C_test[i]);
        if (e > max_err) max_err = e;
    }
    printf("Max error vs reference: %f\n", max_err);
    if (max_err > 1e-2) {
        printf("Test FAILED (expected small error due to quantization, but tolerance exceeded)\n");
        return 1;
    } else {
        printf("Test PASSED\n");
        return 0;
    }
}
